   303→
   304→    const newScore = (session.score || 0) + scorePoints;
   305→    const currentQuestionIndex = (session.current_question_index || 0) + 1;
   306→
   307→    // Adaptive difficulty: increase if correct and no time anomaly, decrease if wrong
