    29→// Get analytics dashboard data (authenticated recruiters only)
    30→router.get('/dashboard', authMiddleware, async (req, res) => {
    31→  try {
    32→    const { start_date, end_date } = req.query;
    33→
    34→    // Default to last 30 days if no dates provided
    35→    const startDate = start_date || new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
    36→    const endDate = end_date || new Date().toISOString();
    37→
    38→    // Page views by type
    39→    const pageViewsResult = await pool.query(`
    40→      SELECT
    41→        event_type,
    42→        COUNT(*) as count,
    43→        COUNT(DISTINCT session_id) as unique_visitors
    44→      FROM events
    45→      WHERE event_type LIKE 'page_view%'
    46→        AND created_at >= $1
    47→        AND created_at <= $2
    48→      GROUP BY event_type
    49→      ORDER BY count DESC
    50→    `, [startDate, endDate]);
    51→
    52→    // Sign-up funnel
    53→    const signupFunnelResult = await pool.query(`
    54→      SELECT
    55→        event_type,
    56→        COUNT(DISTINCT session_id) as sessions
    57→      FROM events
    58→      WHERE event_type IN ('page_view_landing', 'page_view_signup', 'signup_click', 'signup_complete_candidate', 'signup_complete_recruiter')
    59→        AND created_at >= $1
    60→        AND created_at <= $2
    61→      GROUP BY event_type
    62→    `, [startDate, endDate]);
    63→
    64→    // Feature engagement
    65→    const featureEngagementResult = await pool.query(`
    66→      SELECT
    67→        event_type,
    68→        COUNT(*) as count,
    69→        COUNT(DISTINCT user_id) as unique_users
    70→      FROM events
    71→      WHERE event_type IN ('mock_interview_start', 'job_post_created', 'application_submitted', 'assessment_started')
    72→        AND created_at >= $1
    73→        AND created_at <= $2
    74→      GROUP BY event_type
    75→      ORDER BY count DESC
    76→    `, [startDate, endDate]);
    77→
    78→    // Daily visitors (last 30 days)
    79→    const dailyVisitorsResult = await pool.query(`
    80→      SELECT
    81→        DATE(created_at) as date,
    82→        COUNT(DISTINCT session_id) as visitors
    83→      FROM events
    84→      WHERE event_type LIKE 'page_view%'
    85→        AND created_at >= $1
    86→        AND created_at <= $2
    87→      GROUP BY DATE(created_at)
    88→      ORDER BY date ASC
    89→    `, [startDate, endDate]);
    90→
    91→    // Conversion rates
    92→    const landingViews = pageViewsResult.rows.find(r => r.event_type === 'page_view_landing')?.unique_visitors || 0;
    93→    const signupPageViews = pageViewsResult.rows.find(r => r.event_type === 'page_view_signup')?.unique_visitors || 0;
    94→    const signupClicks = signupFunnelResult.rows.find(r => r.event_type === 'signup_click')?.sessions || 0;
    95→    const candidateSignups = signupFunnelResult.rows.find(r => r.event_type === 'signup_complete_candidate')?.sessions || 0;
    96→    const recruiterSignups = signupFunnelResult.rows.find(r => r.event_type === 'signup_complete_recruiter')?.sessions || 0;
    97→    const totalSignups = candidateSignups + recruiterSignups;
    98→
    99→    res.json({
   100→      success: true,
   101→      data: {
   102→        page_views: pageViewsResult.rows,
   103→        signup_funnel: {
   104→          landing_views: landingViews,
   105→          signup_page_views: signupPageViews,
   106→          signup_clicks: signupClicks,
   107→          candidate_signups: candidateSignups,
   108→          recruiter_signups: recruiterSignups,
   109→          total_signups: totalSignups,
   110→          conversion_rate: landingViews > 0 ? ((totalSignups / landingViews) * 100).toFixed(2) : '0.00',
   111→          click_through_rate: landingViews > 0 ? ((signupClicks / landingViews) * 100).toFixed(2) : '0.00'
   112→        },
   113→        feature_engagement: featureEngagementResult.rows,
   114→        daily_visitors: dailyVisitorsResult.rows,
   115→        date_range: { start: startDate, end: endDate }
   116→      }
   117→    });
   118→  } catch (error) {
   119→    console.error('Error fetching analytics:', error);
   120→    res.status(500).json({ error: 'Failed to fetch analytics data' });
   121→  }
   122→});
